function HomeScreen({ onLogout }) {
  const [method, setMethod] = useState(null);

  useEffect(() => {
    (async () => {
      const m = await AsyncStorage.getItem(AUTH_METHOD_KEY);
      setMethod(m);
    })();
  }, []);

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>Home</Text>
        <Text style={styles.hint}>Authenticated via: {method || 'unknown'}</Text>
        <View style={{ height: 12 }} />
        <Button title="Logout" onPress={onLogout} />
      </View>
    </SafeAreaView>
  );
}

export default function App() {
  const [booting, setBooting] = useState(true);
  const [authenticated, setAuthenticated] = useState(false);

  const bootstrap = useCallback(async () => {
    setBooting(true);
    try {
      const flag = await AsyncStorage.getItem(AUTH_FLAG_KEY);
      setAuthenticated(flag === 'true');
    } finally {
      setBooting(false);
    }
  }, []);

  useEffect(() => {
    bootstrap();
  }, [bootstrap]);

  const onAuthed = useCallback(() => {
    setAuthenticated(true);
  }, []);

  const onLogout = useCallback(async () => {
    await AsyncStorage.multiRemove([AUTH_FLAG_KEY, AUTH_METHOD_KEY]);
    setAuthenticated(false);
  }, []);

  if (booting) {
    return (
      <SafeAreaView style={styles.container}>
        <ActivityIndicator />
      </SafeAreaView>
    );
  }

  return authenticated ? <HomeScreen onLogout={onLogout} /> : <LoginScreen onAuthed={onAuthed} />;
}

